const now = new Date();
const prev = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() - 1, 1));
const period = prev.toISOString().slice(0, 7);
const runId = `qa-missing-${period}-${Date.now()}`;
return [{ json: {
  runId,
  period,
  billingApiBaseUrl: 'https://your-billing-api.example.com',
  candidateFeedUrl: 'https://your-billing-api.example.com/api/qa/missing-fee-candidates',
  reportDestinationPrefix: 's3://your-billing-bucket/reports/billing-qa/missing-data/',
  defaultFallbackLabel: 'partner standard rate',
  note: 'Insert the GPT review node and any partner-default lookup nodes before the final report step.'
} }];
